function t(s){return s?s.replace(/<\!\[CDATA\[/g,'').replace(/\]\]>/g,'').replace(/<[^>]+>/g,'').replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&#\d+;/g,'').trim():'';}
function pd(s){if(!s)return null;try{const d=new Date(s);return isNaN(d)?null:d;}catch(e){return null;}}
function parse(xml,src){
  const items=[];
  const rss=[...xml.matchAll(/<item>([\s\S]*?)<\/item>/g)];
  for(const[,raw] of rss){
    const title=t((/<title[^>]*>([\s\S]*?)<\/title>/.exec(raw)||['',''])[1]);
    const link=t((/<link>([\s\S]*?)<\/link>/.exec(raw)||['',''])[1])||t((/<guid[^>]*>([\s\S]*?)<\/guid>/.exec(raw)||['',''])[1]);
    const date=pd(t((/<pubDate>([\s\S]*?)<\/pubDate>/.exec(raw)||['',''])[1]));
    const desc=t((/<description>([\s\S]*?)<\/description>/.exec(raw)||['',''])[1]).slice(0,150);
    if(title&&title.length>5)items.push({src,title,link,date,desc});
  }
  if(!items.length){
    const atom=[...xml.matchAll(/<entry>([\s\S]*?)<\/entry>/g)];
    for(const[,raw] of atom){
      const title=t((/<title[^>]*>([\s\S]*?)<\/title>/.exec(raw)||['',''])[1]);
      const link=(/<link[^>]+href="([^"]+)"/.exec(raw)||['',''])[1];
      const date=pd(t((/<published>([\s\S]*?)<\/published>/.exec(raw)||/<updated>([\s\S]*?)<\/updated>/.exec(raw)||['',''])[1]));
      const desc=t((/<summary[^>]*>([\s\S]*?)<\/summary>/.exec(raw)||['',''])[1]).slice(0,150);
      if(title&&title.length>5)items.push({src,title,link,date,desc});
    }
  }
  return items;
}

const res=await Promise.allSettled(S.map(async s=>{
  const c=new AbortController();
  const timer=setTimeout(()=>c.abort(),7000);
  try{
    const r=await fetch(s.u,{signal:c.signal,headers:{'User-Agent':'Mozilla/5.0 (compatible; NewsBot/1.0)'}});
    return parse(await r.text(),s.n);
  }catch(e){return [];}finally{clearTimeout(timer);}
}));

const now=new Date();
const cutoff=new Date(now-48*3600*1000);
const seen=new Set();
const articles=[];
for(const r of res){
  if(r.status!=='fulfilled')continue;
  for(const a of r.value){
    const k=a.title.toLowerCase().slice(0,40);
    if(seen.has(k))continue;
    seen.add(k);
    if(a.date&&a.date>=cutoff)articles.push(a);
  }
}
articles.sort((a,b)=>(b.date||new Date(0))-(a.date||new Date(0)));
const fetched=res.filter(r=>r.status==='fulfilled'&&r.value.length>0).length;
return [{json:{articles:articles.slice(0,40),fetched,total:S.length}}];

const data = $input.first().json;
const today = new Date().toLocaleDateString('ru-RU', {day:'numeric',month:'long',year:'numeric'});
const articles = data.articles || [];
const list = articles.map((a,i) => (i+1)+'. ['+a.src+'] '+a.title+(a.desc?' — '+a.desc:'')).join('\n');
const userContent = 'Сегодня ' + today + '. Источников: ' + (data.fetched||'?') + '/' + (data.total||'?') + '. Свежих статей: ' + articles.length + '.\n\n' + list;

const systemPrompt = 'Ты Зевс — ИИ-ассистент Дениса Видякова. Пишешь ежедневный дайджест ИИ-новостей на русском для Telegram-канала Студия ЧЕ (видеомонтаж и нейросети). Строгий фильтр: только новости про ИИ — новые модели, релизы нейросетей, новые фичи, обновления ИИ-инструментов. Начни с заголовка: ДАЙДЖЕСТ ИИ-НОВОСТЕЙ — [дата из запроса]. Затем ровно 7 новостей с эмодзи, каждая 2-3 предложения с аналитикой что это значит для видеомейкеров и контент-мейкеров. В конце — 2-3 предложения общего вывода о трендах. Только обычный текст без Markdown.';

const body = JSON.stringify({
  model: 'claude-opus-4-6',
  max_tokens: 1500,
  stream: false,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
});

return [{ json: { body, articleCount: articles.length } }];

const res = $input.first().json;
const textBlock = res.content ? res.content.find(c => c.type === 'text') : null;
if (!textBlock) return [{ json: { ok: false } }];

const post = textBlock.text.trim();
const BOT_TOKEN = $env.TELEGRAM_BOT_TOKEN;
const DENIS_ID = 211279650;
const PWA_URL = 'https://mycheagent.ru/webhook/pwa-data';
const id = 'digest_' + Date.now();

// Save to pending store
await fetch(PWA_URL, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ action: 'savePending', id, text: post })
});

// Save to PWA reports too
await fetch(PWA_URL, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ action: 'addReport', text: '📰 ' + post })
});

// Send to Denis with approve button
await fetch(`https://api.telegram.org/bot${BOT_TOKEN}/sendMessage`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    chat_id: DENIS_ID,
    text: post,
    reply_markup: {
      inline_keyboard: [[
        { text: '✅ Опубликовать в канал', callback_data: `channel:${id}` },
        { text: '❌ Не публиковать', callback_data: `channel_skip:${id}` }
      ]]
    }
  })
});

return [{ json: { ok: true } }];
